import React, { useEffect, useState } from 'react';
import { updateSeo } from '../../utils/seoHelper';
import emailjs from '@emailjs/browser';
import { assertEmailJsConfig } from '../../constants/emailjs';
import styles from './Contact.module.css';

function Contact() {
  const [form, setForm] = useState({
    name: '',
    email: '',
    phone: '',
    message: ''
  });

  const [status, setStatus] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    updateSeo({
      title: 'Contact - Kognivex',
      description: 'Contact Kognivex for partnerships and development services.',
    });
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    setLoading(true);
    setStatus('');

    let config;
    try {
      config = assertEmailJsConfig();
    } catch (err) {
      console.error('EmailJS config error:', err);
      setStatus(err.message);
      setLoading(false);
      return;
    }

    emailjs.send(
      config.serviceId,
      config.templateId,
      {
        from_name: form.name,
        from_email: form.email,
        phone: form.phone,
        message: form.message,
      },
      config.publicKey
    )
    .then(() => {
      setStatus('✅ Message sent successfully!');
      setForm({
        name: '',
        email: '',
        phone: '',
        message: ''
      });
    })
    .catch((error) => {
      console.error('EmailJS send failed:', error);
      setStatus('❌ Failed to send message. Try again.');
    })
    .finally(() => {
      setLoading(false);
    });
  };

  return (
    <main className={styles.contactPage}>
      <div className={styles.container}>
        {/* HEADER */}
        <div className={styles.header}>
          <h1>Contact Us</h1>
          <p>
            Let’s discuss your project or idea. We’ll help you build scalable solutions.
          </p>
        </div>

        {/* GRID */}
        <div className={styles.grid}>
          {/* LEFT INFO */}
          <div className={styles.infoCard}>
            <h2>Get in Touch</h2>
            <p>
              Reach out for web apps, SaaS platforms, or enterprise solutions.
            </p>

            <div className={styles.contactDetails}>
              <p><strong>Email:</strong> info.kognivex@gmail.com</p>
              <p><strong>Phone:</strong> +91 93817 97198</p>
              <p><strong>Location:</strong> India</p>
            </div>

            <div className={styles.note}>
              We usually respond within 24 hours.
            </div>
          </div>

          {/* FORM */}
          <form onSubmit={handleSubmit} className={styles.form}>
            <h2>Send a Message</h2>

            <div className={styles.inputGroup}>
              <input
                type="text"
                name="name"
                placeholder="Full Name"
                value={form.name}
                onChange={handleChange}
                required
                className={styles.input}
              />
            </div>

            <div className={styles.inputGroup}>
              <input
                type="email"
                name="email"
                placeholder="Email Address"
                value={form.email}
                onChange={handleChange}
                required
                className={styles.input}
              />
            </div>

            <div className={styles.inputGroup}>
              <input
                type="tel"
                name="phone"
                placeholder="Phone Number"
                value={form.phone}
                onChange={handleChange}
                className={styles.input}
              />
            </div>

            <div className={styles.inputGroup}>
              <textarea
                name="message"
                placeholder="Your Message"
                value={form.message}
                onChange={handleChange}
                required
                className={`${styles.input} ${styles.textarea}`}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className={styles.submitBtn}
            >
              {loading ? 'Sending...' : 'Send Message'}
            </button>

            {status && (
              <p className={styles.statusMessage}>{status}</p>
            )}
          </form>
        </div>
      </div>
    </main>
  );
}

export default Contact;
